const notionDocs = $('Retrieve Notion Pages').all();
const substackDocs = $('Retrieve Substack Posts').all();
const linkedinDocs = $('Retrieve LinkedIn Posts').all();

let ragContext = '### RELEVANT HISTORICAL CONTENT & KNOWLEDGE (RAG) ###\n\n';

function addDocs(docs, sourceName) {
  if (docs.length === 0) return;
  docs.forEach((doc, idx) => {
    const metadata = doc.json.metadata || {};
    const title = metadata.title || 'Untitled';
    const content = doc.json.pageContent || doc.json.content || '';
    ragContext += `[Source: ${sourceName} | Title: ${title}]\n`;
    ragContext += `Content: ${content.substring(0, 1000)}\n`;
    ragContext += `---\n\n`;
  });
}

addDocs(notionDocs, 'Notion');
addDocs(substackDocs, 'Substack');
addDocs(linkedinDocs, 'LinkedIn');

return [{ json: { rag_context: ragContext } }];

const ragContext = $('Format RAG Context').first()?.json?.rag_context || '';
const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

return [{ json: { text: 'No weekly activity data (retrieval only).', rag_context: ragContext, ref_map: {}, giusy_persona: persona, comments_list: [], messages_list: [], invitations_list: [] } }];

